// Promise version
function delayPrintWithPromise() {
  return new Promise(function(resolve) {
    setTimeout(function() {
      console.log('Hello, World!');
      resolve();
    }, 2000);
  });
}

// async/await version
async function delayPrintWithAsyncAwait() {
  await delayPrintWithPromise();
}

// Test the functions
delayPrintWithPromise().then(function() {
  console.log('Promise version done.');
});

delayPrintWithAsyncAwait().then(function() {
  console.log('Async/Await version done.');
});

var arr = ['apple', 'orange', 'banana', 'apple', 'orange'];
var uniqueArr = [...new Set(arr)];
