async function fetchData() {
  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/posts');
    const data = await response.json();
    console.log(data);
  } catch (error) {
    console.error('Error:', error);
  }
}
fetchData();

class Person {
  constructor(name, age) {
    this.name = name;
    this.age = age;
  }

  sayHello() {
    console.log(`Hello, my name is ${this.name} and I am ${this.age} years old.`);
  }
}

let john = new Person('John', 30);
john.sayHello(); // Expected output: 'Hello, my name is John and I am 30 years old.'

const arr = [1, 2, 3, 4, 5];

const result = arr.reduce((accumulator, currentValue) => {
  return accumulator + currentValue;
}, 0);

console.log(result); // Expected output: 15

function add(initialValue) {
  return function(number) {
    return initialValue + number;
  };
}

const addFive = add(5);
console.log(addFive(3)); // Expected output: 8

function simulateAsync(ms) {
  return new Promise(resolve => {
    setTimeout(() => {
      resolve(ms);
    }, ms);
  });
}

simulateAsync(3000).then(value => {
  console.log(value); // Expected output: 3000 (after 3 seconds)
});

async function printSimulatedValue() {
  // Await for the promise to resolve
  const value = await simulateAsync(3000);

  // Log the value
  console.log(value); // Expected output: 3000 (after 3 seconds)
}

// Call the async function
printSimulatedValue();

function makeCounter() {
  let count = 0;

  return function() {
    count++;
    console.log(count); // Output: Incrementing number starting from 1
  };
}

let counter = makeCounter();

// Call the counter
counter();
counter();
counter();

function mergeObjects(obj1, obj2) {
  return Object.assign({}, obj1, obj2);
}

let obj1 = { a: 1, b: 2 };
let obj2 = { b: 3, c: 4 };

let result = mergeObjects(obj1, obj2);
console.log(result); // Expected output: { a: 1, b: 3, c: 4 }

function asyncProcess() {
  return new Promise(resolve => {
    setTimeout(() => {
      resolve("Completed!"); // Resolves after 1 second
    }, 1000);
  });
}

// Create a promise chain
asyncProcess()
  .then(result => {
    console.log(result); // Expected output: Completed!
  });

async function callAsyncProcess() {
  let result = await asyncProcess(); // Waiting for the promise to resolve
  console.log(result); // Expected output: Completed!
}

callAsyncProcess();

